<section class="admin-page-head"><div><p class="eyebrow">FACTURARE / MAPPER</p><h1>Poziționare câmpuri</h1><p>Doar variabilele din lista permisă pot fi mapate în document.</p></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><div class="admin-two-columns"><section class="admin-panel"><form method="get"><label>Versiune șablon<select name="version_id" onchange="this.form.submit()"><?php foreach($versions as $version): ?><option value="<?= (int)$version['id'] ?>" <?= $versionId===$version['id']?'selected':'' ?>><?= e($version['template_name']) ?> v<?= (int)$version['version_no'] ?></option><?php endforeach; ?></select></label></form><div class="invoice-mapper-canvas"><?php foreach($fields as $field): ?><span style="left:<?= (float)$field['x'] ?>%;top:<?= (float)$field['y'] ?>%;width:<?= (float)$field['width'] ?>%;height:<?= (float)$field['height'] ?>%" title="<?= e($field['variable_name']) ?>"><?= e($field['variable_name']) ?></span><?php endforeach; ?></div></section><aside><form class="admin-panel" method="post" action="<?= e(url('/admin/facturare/sabloane/mapper')) ?>"><?= csrf_field() ?><input type="hidden" name="version_id" value="<?= $versionId ?>"><h2>Adaugă un câmp</h2><label>Variabilă<select name="variable_name"><?php foreach(['invoice.number','invoice.issue_date','invoice.due_date','issuer.legal_name','issuer.tax_id','issuer.address','customer.name','customer.tax_id','customer.address','items.table','totals.subtotal','totals.vat','totals.grand_total','invoice.notes'] as $variable): ?><option><?= e($variable) ?></option><?php endforeach; ?></select></label><label>Tip<select name="field_type"><option>text</option><option>table</option><option>array</option><option>image</option></select></label><div class="admin-form-grid"><label>Pagina<input type="number" name="page_no" value="1"></label><label>X %<input type="number" step="0.1" name="x" value="8"></label><label>Y %<input type="number" step="0.1" name="y" value="8"></label><label>Lățime %<input type="number" step="0.1" name="width" value="40"></label><label>Înălțime %<input type="number" step="0.1" name="height" value="5"></label><label>Font<input type="number" name="font_size" value="10"></label></div><button class="admin-button" type="submit">Adaugă în șablon</button></form></aside></div>
